下面是一个完整、实用的 JavaScript **debounce** 函数实现，包含 TypeScript 类型注解和常见变体：

```javascript
/**
 * 创建一个防抖函数
 * @param {Function} fn      要执行的回调函数
 * @param {number}   delay   延迟时间（毫秒）
 * @param {Object}   options 可选配置
 * @param {boolean}  options.leading  是否在延迟开始前执行（默认 false）
 * @param {boolean}  options.trailing 是否在延迟结束后执行（默认 true）
 * @returns {Function} 防抖后的函数，带 .cancel() 和 .flush() 方法
 */
function debounce(fn, delay, options = {}) {
  const { leading = false, trailing = true } = options;

  let timer = null;          // 定时器句柄
  let lastArgs = null;       // 最近一次调用的参数
  let lastContext = null;    // 最近一次调用的 this 上下文
  let lastCallTime = 0;     // 上一次调用 debounced 函数的时间戳
  let result = undefined;   // 最后一次执行 fn 的返回值

  // 检查是否应该立即执行（leading edge）
  function shouldInvoke(time) {
    const timeSinceLastCall = time - lastCallTime;
    return (
      lastCallTime === 0 ||         // 第一次调用
      timeSinceLastCall >= delay || // 间隔已超过 delay
      timeSinceLastCall < 0         // 系统时间回拨
    );
  }

  // 执行回调
  function invokeFunc(time) {
    const args = lastArgs;
    const context = lastContext;
    lastArgs = null;
    lastContext = null;
    lastCallTime = time;
    result = fn.apply(context, args);
    return result;
  }

  // 启动 trailing 定时器
  function startTimer(pendingTimer, waitTime) {
    clearTimeout(timer);
    timer = setTimeout(pendingTimer, waitTime);
  }

  // trailing 边界结束时执行
  function trailingEdge(time) {
    timer = null;
    if (trailing && lastArgs) {
      return invokeFunc(time);
    }
    lastArgs = null;
    lastContext = null;
  }

  // 核心防抖函数
  function debounced(...args) {
    const time = Date.now();
    const isInvoking = shouldInvoke(time);

    lastArgs = args;
    lastContext = this;

    if (isInvoking) {
      if (leading) {
        // leading 模式：立即执行，并清除 trailing
        if (timer === null && trailing) {
          // 还有 trailing 等待，不处理
        }
        const resultLeading = invokeFunc(time);
        // 重新启动 trailing 定时器，阻止下一次 trailing 触发
        if (trailing) {
          startTimer(trailingEdge.bind(null, time + delay), delay);
        }
        return resultLeading;
      }
    }

    // trailing 模式（或 leading 但上一次调用还在 delay 内）
    if (timer === null && trailing) {
      startTimer(trailingEdge.bind(null, time + delay), delay);
    }

    return result;
  }

  // 取消防抖，终止未执行的调用
  debounced.cancel = function () {
    clearTimeout(timer);
    timer = null;
    lastArgs = null;
    lastContext = null;
    lastCallTime = 0;
  };

  // 立即执行当前等待中的调用
  debounced.flush = function () {
    if (timer !== null) {
      const time = Date.now();
      trailingEdge(time);
    }
    return result;
  };

  return debounced;
}
```

---

## 使用示例

### 1️⃣ 基本用法（trailing 模式，默认）

```javascript
const saveInput = debounce((text) => {
  console.log('保存:', text);
}, 300);

// 用户快速输入，只有最后一次输入后 300ms 才真正执行
input.addEventListener('input', (e) => saveInput(e.target.value));
```

### 2️⃣ leading 模式（先执行一次，再防抖）

```javascript
const logClick = debounce(
  () => console.log('点击！'),
  1000,
  { leading: true, trailing: false }  // 立即执行，不延迟收尾
);

button.addEventListener('click', logClick);
// 连续快速点击 → 只有第一次立即触发，后续忽略
```

### 3️⃣ leading + trailing（两端都触发）

```javascript
const search = debounce(
  (q) => fetch(`/search?q=${q}`),
  500,
  { leading: true, trailing: true }
);
// 快速输入"abc"：a 立即触发一次，c 之后 500ms 再触发一次
```

### 4️⃣ 取消与立即刷新

```javascript
const debouncedFn = debounce(() => { /* ... */ }, 2000);

// 取消等待中的调用
debouncedFn.cancel();

// 立即执行等待中的调用
debouncedFn.flush();
```

### 5️⃣ React 组件中使用

```jsx
import { useMemo } from 'react';

function SearchBox() {
  const debouncedSearch = useMemo(
    () => debounce((q) => fetchSearch(q), 500),
    []
  );

  return <input onChange={(e) => debouncedSearch(e.target.value)} />;
}
```

---

## 核心概念速查

| 模式 | `leading` | `trailing` | 行为 |
|------|-----------|------------|------|
| **默认 trailing** | `false` | `true` | 停止连续调用后 delay ms 执行一次 |
| **leading** | `true` | `false` | 立即执行第一次，后续连续调用被忽略 |
| **两端触发** | `true` | `true` | 第一次立即执行，最后一次延迟执行 |
| **仅首尾**（lodash 风格） | `true` | `true` | 同上，完整的首尾防抖 |

**防抖 vs 节流：**
- **debounce** → 防抖：高频触发后，**等停下来了**才执行（适合输入搜索、auto-save）
- **throttle** → 节流：高频触发时，**固定频率**执行（适合滚动、resize）

